@startuml
left to right direction
skinparam classAttributeIconSize 0

actor Maker as Maker
actor Solver as Solver

class Puzzle {
  grid dimension
  complexity
}

class RowsColumns {
  priorities
  constraints
}

class Solutions {
  general
  row/column
}

class Pixels {
  black
  white
}

Maker "1" -- "*" Puzzle : design
Puzzle "*" -- "1" Solver : solve

Puzzle "1" *-- "*" RowsColumns : contains
Puzzle "1" -- "1" Solutions

RowsColumns "*" -- "*" Solutions

RowsColumns "1" *-- "*" Pixels : contains
@enduml
